import{_ as o,o as r,c as d,a4 as n}from"./chunks/framework.E9a65_Io.js";const c=JSON.parse('{"title":"John 🤽‍♂️","description":"","frontmatter":{},"headers":[],"relativePath":"john-🤽‍♂️.md","filePath":"john-🤽‍♂️.md"}'),a={name:"john-🤽‍♂️.md"};function h(e,t,i,l,s,j){return r(),d("div",null,[...t[0]||(t[0]=[n('<h1 id="john-🤽‍♂️" tabindex="-1">John 🤽‍♂️ <a class="header-anchor" href="#john-🤽‍♂️" aria-label="Permalink to &quot;John 🤽‍♂️&quot;">​</a></h1><p>John &quot;水球&quot; 是笨猫探穴中一位传奇的水球运动员，同时也是水水世界最著名的 NPC。他以狂热水球爱好者和庞大的&quot;John 家族&quot;而闻名——没人知道他到底有多少个亲戚，只知道他们全都是以 &quot;J&quot; 开头命名的。</p><p>据说 John 原本只是一个普通的矿工，直到有一天他在水域地层挖到了一个魔法水球。从那以后，他的人生彻底改变了——他成立了&quot;水球联盟&quot;，在世界二和水水世界之间来回穿梭，四处发任务让玩家帮他找各种稀奇古怪的东西。有人说他是个疯子，有人说他是个天才，但没人能否认：他给的奖励是真的香。</p><p>他的口号是：&quot;没有什么是水球解决不了的，如果有，就再来一个水球。&quot;</p><h3 id="john-可以索要的东西" tabindex="-1">John 可以索要的东西 <a class="header-anchor" href="#john-可以索要的东西" aria-label="Permalink to &quot;John 可以索要的东西&quot;">​</a></h3><p>John 可以索要很多东西，以下是清单：</p><table tabindex="0"><thead><tr><th>角色</th><th>名称</th></tr></thead><tbody><tr><td>🤽🏻</td><td>jonah</td></tr><tr><td>🤽🏼</td><td>jackson</td></tr><tr><td>🤽🏽</td><td>don</td></tr><tr><td>🤽🏾</td><td>ron</td></tr><tr><td>🤽🏿</td><td>johan（不是 jonah）</td></tr><tr><td>🤽</td><td>jim</td></tr><tr><td>🤽🏻‍♂️</td><td>shawn</td></tr><tr><td>🤽🏼‍♂️</td><td>jay</td></tr><tr><td>🤽🏽‍♂️</td><td>rowan</td></tr><tr><td>🤽🏾‍♂️</td><td>jory</td></tr><tr><td>🤽🏿‍♂️</td><td>jordan</td></tr><tr><td>🤽‍♀️</td><td>jane</td></tr><tr><td>🤽🏻‍♀️</td><td>janine</td></tr><tr><td>🤽🏼‍♀️</td><td>joan</td></tr><tr><td>🤽🏽‍♀️</td><td>johanna（joan 的妹妹）</td></tr><tr><td>🤽🏾‍♀️</td><td>jocelyn</td></tr><tr><td>🤽🏿‍♀️</td><td>rowhen</td></tr><tr><td>🐃</td><td>john 的宠物</td></tr><tr><td>evil john</td><td>（本页某处有图片）</td></tr><tr><td>josh</td><td>（太可怕了，不适合在本 wiki 展示）</td></tr></tbody></table><h3 id="如何获得-evil-john" tabindex="-1">如何获得 Evil John <a class="header-anchor" href="#如何获得-evil-john" aria-label="Permalink to &quot;如何获得 Evil John&quot;">​</a></h3><p>拒绝 John 的 5 次请求即可获得 Evil John（每次挖到与你最稀有矿石相同稀有度的矿石时，请求会生成，上限为无穷小）。当你这样做时，John 的眼睛会变红，你会获得一个 CLT。注意不要因为害怕而关闭游戏，否则你得重来！</p><h3 id="john-的任务奖励" tabindex="-1">John 的任务奖励 <a class="header-anchor" href="#john-的任务奖励" aria-label="Permalink to &quot;John 的任务奖励&quot;">​</a></h3><p>John 的任务不会重复出现，因此他总共只会弹出 20 次（假设你每次都给他想要的——但这是不可能的，因为你需要 evil john 😦 ）</p><ul><li><strong>完成 1 个任务</strong>：获得 John 的传家宝齿轮，效果为（已完成船只事件数）^1.1 倍洞穴幸运（满级时约 1k 倍）</li><li><strong>完成 5 个任务</strong>：获得 John 的水球——如果你没抽到变体洞穴，它会重新判定一次，所以你有机会抽到洞穴！！！</li><li><strong>完成 10 个任务</strong>：解锁 <strong><a href="./hypermark-checkminator.html">Hypermark Checkminator</a></strong> 镐子！</li><li><strong>完成 15 个任务</strong>：获得他超级酷的帽子（不会改变他的外观，他还有备用的）——如果你不向左挖掘，移动速度提升 1.15 倍（重复次数 1.15x）</li><li><strong>完成 20 个任务</strong>：John 会向你敞开心扉，讲述他的人生故事。之后你可以参观 John 在世界二的家（你可以在他家里偷走 John 的赌场筹码，从而实现事件管理器自动化）</li></ul><hr><p><em>由 <a href="https://the-silly-caverns.fandom.com/wiki/John_%F0%9F%A4%BD%E2%80%8D%E2%99%82%EF%B8%8F" target="_blank" rel="noreferrer">笨猫探穴 Wiki</a> 汉化</em></p>',14)])])}const p=o(a,[["render",h]]);export{c as __pageData,p as default};
